INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee2860-0000-0000-0000-000000000008', 'A deed calls to run {{rec:f2}} ft to an original iron rod, but the genuine, undisturbed original rod is found at a measured {{meas:f2}} ft. Applying the controlling-monument rule, what distance (ft) do you hold to the corner?', 'numeric_input', '[]'::jsonb, '0', 'A found genuine original monument controls over the record distance, so the boundary is held to the rod at {{meas:f2}} ft; the {{rec:f2}} ft call yields. The answer is {{_answer}} ft.', 'easy', 'c100001c-0000-0000-0000-00000000001c', NULL, ARRAY['buildout','module-28','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee2850-0000-0000-0000-000000000008', 0.01);
