-- 359_buildout_m28.sql (GENERATED) — fill empty lessons for "RPLS Exam Review — Practical Surveying"
-- Module c100001c-0000-0000-0000-00000000001c. Namespaced by tag 'buildout' / created_by 'buildout:m28' so pre-existing rows are untouched.
BEGIN;
DELETE FROM question_bank     WHERE module_id='c100001c-0000-0000-0000-00000000001c' AND 'buildout' = ANY(tags);
DELETE FROM flashcards        WHERE module_id='c100001c-0000-0000-0000-00000000001c' AND 'buildout' = ANY(tags);
DELETE FROM problem_templates WHERE module_id='c100001c-0000-0000-0000-00000000001c' AND created_by='buildout:m28';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Latitude = d·cos(bearing), Departure = d·sin(bearing); signs follow the quadrant (N+/S-, E+/W-).','Inverse: distance = hypot(dE, dN); azimuth = atan2(dE, dN) reduced to 0-360 deg.','Forward (coordinate) problem: N2 = N1 + d·cos(Az), E2 = E1 + d·sin(Az).']::text[], learning_objectives=ARRAY['Convert between bearings/azimuths and latitude/departure for any quadrant.','Compute the inverse (distance and azimuth) and the forward (coordinate) problem from rectangular coordinates.','Carry latitude/departure bookkeeping through a multi-course traverse to find a closing coordinate.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='0c8c3b20-547c-40ac-9a95-f3864a116b2b';
DELETE FROM lesson_blocks WHERE lesson_id='0c8c3b20-547c-40ac-9a95-f3864a116b2b';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Grid = Ground x CSF; Ground = Grid / CSF, where CSF = grid scale factor x elevation factor.','Geodetic azimuth = grid azimuth + convergence (gamma); the second-term (t-T) correction is usually negligible for short lines.','H = h - N converts a GNSS ellipsoidal height to an orthometric elevation.']::text[], learning_objectives=ARRAY['Apply the combined scale factor to convert between ground and grid distances on the Texas State Plane system.','Distinguish grid azimuth from geodetic azimuth using the convergence angle.','Convert ellipsoidal heights to orthometric heights with the geoid relationship.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='ca5cbe08-3766-4389-be5b-513e17479be8';
DELETE FROM lesson_blocks WHERE lesson_id='ca5cbe08-3766-4389-be5b-513e17479be8';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Priority of calls: senior rights > written intent > calls for monuments (natural then artificial) > courses (bearings) > distances > area.','When a found original monument controls, hold the monument and prorate or adjust the record distance to it.','A retracement surveyor follows the footsteps of the original surveyor; the goal is to find where the lines were, not where they should have been.']::text[], learning_objectives=ARRAY['Rank conflicting boundary evidence using the priority of calls.','Apply the rule that a controlling monument overrides a record distance, and compute the corrected distance accordingly.','Explain footsteps/retracement doctrine and the role of original-survey evidence in Texas.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='2aa90c7c-c09a-4dc0-9c2c-bd14f4f9c365';
DELETE FROM lesson_blocks WHERE lesson_id='2aa90c7c-c09a-4dc0-9c2c-bd14f4f9c365';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Angular misclosure for a closed polygon: sum of interior angles should equal (n-2)*180 deg; distribute the misclosure equally.','Linear misclosure = hypot(sum of latitudes, sum of departures); precision = perimeter / linear misclosure.','Compass rule correction to a course is proportional to its length: correction = -(misclosure) x (course length / perimeter).']::text[], learning_objectives=ARRAY['Balance angular misclosure and compute corrected azimuths around a closed traverse.','Compute latitudes/departures, linear misclosure, and the precision ratio of a closed traverse.','Adjust a traverse by the compass (Bowditch) rule and confirm the closure.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='f3aa8c68-5638-4f0c-9fb7-aed7fb503220';
DELETE FROM lesson_blocks WHERE lesson_id='f3aa8c68-5638-4f0c-9fb7-aed7fb503220';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=45, key_takeaways=ARRAY['Shoelace area = 1/2 |sum of (x_i*y_{i+1} - x_{i+1}*y_i)|; close the polygon back to the first point.','Single proportion distributes excess/deficiency along one line; double proportion locates an interior corner from four controlling monuments.','1 acre = 43,560 sq ft; carry enough decimals so the rounded acreage is correct.']::text[], learning_objectives=ARRAY['Compute parcel area from coordinates using the shoelace (coordinate) method.','Apply single and double proportionate measurement to distribute excess or deficiency.','Divide a parcel into specified areas and convert between square feet and acres.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='370abca8-6a2f-4e77-8c73-9615d592af9a';
DELETE FROM lesson_blocks WHERE lesson_id='370abca8-6a2f-4e77-8c73-9615d592af9a';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=40, key_takeaways=ARRAY['Curve parts: T = R tan(I/2), L = R*I (I in radians) = pi*R*I/180, LC = 2R sin(I/2).','Tangent-grade elevation = start + grade% x distance / 100; cut/fill = design - ground.','Average-end-area volume = L/2 x (A1 + A2); divide by 27 for cubic yards.']::text[], learning_objectives=ARRAY['Compute the principal parts of a simple horizontal curve (T, L, LC, M, E) from R and I.','Compute design elevations on a tangent grade and cut/fill at grade stakes.','Estimate earthwork volume by the average-end-area method.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='da06cbbe-3ed2-42aa-9e15-14807265501c';
DELETE FROM lesson_blocks WHERE lesson_id='da06cbbe-3ed2-42aa-9e15-14807265501c';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['RTK gives cm-level positions in real time from a base-rover pair; static is most accurate; RTN uses a network of CORS-like stations.','A site calibration (localization) fits GNSS positions to local control via a horizontal best-fit and a vertical (inclined plane) fit.','Low PDOP, redundant occupations, and multipath-free sites give the most reliable GNSS positions.']::text[], learning_objectives=ARRAY['Distinguish RTK, static, and network-RTK (RTN) GNSS methods and their accuracies.','Localize/calibrate GNSS to a local coordinate system and apply the ground-to-grid relationship.','Identify error sources (multipath, PDOP, ionosphere) and quality indicators in GNSS work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='42f97e15-6fd1-44a9-aedb-9e67438340eb';
DELETE FROM lesson_blocks WHERE lesson_id='42f97e15-6fd1-44a9-aedb-9e67438340eb';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['TBPELS (the Texas Board) licenses RPLSs and adopts the rules; the TSPS Manual of Practice sets survey categories and condition tiers.','Relative accuracy ratio = baseline / positional error; categories specify minimum ratios and positional tolerances.','A compliant plat shows basis of bearing, monuments found/set, the surveyor''s seal/signature/date, and a proper legal description.']::text[], learning_objectives=ARRAY['Identify the TBPELS rules and TSPS Manual of Practice categories that govern Texas land surveys.','Apply relative-accuracy and positional-tolerance standards to a survey result.','List the mandatory elements and certification requirements of a Texas land-survey plat.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='366b16ac-30f6-4400-b7c7-051edd5bf873';
DELETE FROM lesson_blocks WHERE lesson_id='366b16ac-30f6-4400-b7c7-051edd5bf873';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=50, key_takeaways=ARRAY['Practical problems chain the four COGO operations; tabulate and label units to avoid propagating errors.','Gap/overlap = the signed difference between adjoining record/measured positions along a common line.','When a monument controls, the corrected distance is the measured distance to the monument, not the deed call.']::text[], learning_objectives=ARRAY['Work multi-step practical problems combining closure, area, curves, and proportionate measurement.','Resolve a record-versus-monument conflict by holding the monument and correcting the distance.','Compute gap/overlap widths and corrected lot frontages numerically.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7c610f13-f9d4-454f-b989-9103f108ef0a';
DELETE FROM lesson_blocks WHERE lesson_id='7c610f13-f9d4-454f-b989-9103f108ef0a';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Triage by point value; bank quick single-step items, then invest time in multi-stage problems.','Most lost points come from sign/quadrant errors, unit mix-ups, and calculator mode (deg vs rad).','Always write the formula and substitute with units so graders can award partial credit.']::text[], learning_objectives=ARRAY['Apply a time-management strategy for the full-length practical exam.','Avoid the most common computational and unit errors under exam conditions.','Use a structured method to show work and earn partial credit.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='2a4b0b8a-b0d9-4ccb-a718-ef836cee7547';
DELETE FROM lesson_blocks WHERE lesson_id='2a4b0b8a-b0d9-4ccb-a718-ef836cee7547';
  'eeee2850-0000-0000-0000-000000000001', 'Latitude and departure of a course', 'Resolve a bearing-and-distance course into its latitude and departure components.', 'RPLS Practical — Coordinate Geometry', 'Latitude and departure', 'numeric_input', 'easy', 'A course runs N {{ang}} deg E for a distance of {{dist:f2}} ft. Compute the DEPARTURE (east-west component) of this course in feet.', 'dist*sin(toRad(ang))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"ang","type":"integer","min":15,"max":75},{"name":"dist","type":"float","min":150,"max":700,"decimals":2}]'::jsonb, '[{"name":"lat","formula":"dist*cos(toRad(ang))"}]'::jsonb, '[{"step_number":1,"title":"Departure formula","formula":"Dep = d sin(alpha)","calculation_template":"{{dist:f2}} x sin({{ang}} deg)"},{"step_number":2,"title":"Compute","result_template":"Departure = {{_answer}} ft (east, positive)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Departure = d sin(alpha) = {{dist:f2}} x sin({{ang}} deg) = {{_answer}} ft. (The latitude, d cos(alpha), would be {{lat:f2}} ft north.)', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000002', 'Linear misclosure of a closed traverse', 'Compute the linear misclosure from the summed latitudes and departures of a closed traverse.', 'RPLS Practical — Traverse', 'Misclosure', 'numeric_input', 'medium', 'After summing all courses of a closed-loop traverse, the latitudes total {{sumLat:f3}} ft and the departures total {{sumDep:f3}} ft. Compute the LINEAR MISCLOSURE (ft).', 'hypot(sumLat, sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"sumLat","type":"float","min":-0.2,"max":0.2,"decimals":3},{"name":"sumDep","type":"float","min":-0.2,"max":0.2,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure formula","formula":"sqrt(sumLat^2 + sumDep^2)","calculation_template":"sqrt(({{sumLat:f3}})^2 + ({{sumDep:f3}})^2)"},{"step_number":2,"title":"Compute","result_template":"Linear misclosure = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Linear misclosure is the hypotenuse of the latitude and departure misclosures: hypot({{sumLat:f3}}, {{sumDep:f3}}) = {{_answer}} ft.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000003', 'Area of a right-triangular parcel by coordinates', 'Compute parcel area in acres from the leg dimensions of a right-triangular lot.', 'RPLS Practical — Area', 'Area by coordinates', 'numeric_input', 'medium', 'A triangular parcel has perpendicular legs of {{a:f2}} ft (east) and {{b:f2}} ft (north) meeting at a right angle. Using the coordinate (shoelace) method, compute the parcel AREA in ACRES (1 acre = 43,560 sq ft).', '(0.5*a*b)/43560', '{"decimals":3,"unit":"acres","tolerance":0.005}', '[{"name":"a","type":"float","min":200,"max":600,"decimals":2},{"name":"b","type":"float","min":200,"max":600,"decimals":2}]'::jsonb, '[{"name":"sf","formula":"0.5*a*b"}]'::jsonb, '[{"step_number":1,"title":"Triangle area in square feet","formula":"1/2 x base x height","calculation_template":"0.5 x {{a:f2}} x {{b:f2}} = {{sf:f2}} sq ft"},{"step_number":2,"title":"Convert to acres","formula":"sq ft / 43560","result_template":"{{sf:f2}} / 43560 = {{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'By coordinates the area reduces to 1/2 x leg x leg = 0.5 x {{a:f2}} x {{b:f2}} = {{sf:f2}} sq ft; dividing by 43,560 gives {{_answer}} acres.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000004', 'Single-proportion corrected lot frontage', 'Distribute a measured surplus or deficiency equally among record lots by single proportion.', 'RPLS Practical — Proportionate Measurement', 'Single proportion', 'numeric_input', 'medium', 'A block of {{n}} equal lots was platted, each with a record frontage of {{rec:f2}} ft (record total {{recTotal:f2}} ft). A resurvey finds the actual measured distance between the original block corners is {{meas:f2}} ft. By single proportionate measurement, what is the corrected frontage (ft) of each lot?', '(n*rec+surplus)/n', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"n","type":"integer","min":4,"max":10},{"name":"rec","type":"float","min":48,"max":60,"decimals":2},{"name":"surplus","type":"float","min":-3,"max":4,"decimals":2}]'::jsonb, '[{"name":"recTotal","formula":"n*rec"},{"name":"meas","formula":"n*rec+surplus"}]'::jsonb, '[{"step_number":1,"title":"Record total","formula":"n x record","calculation_template":"{{n}} x {{rec:f2}} = {{recTotal:f2}} ft"},{"step_number":2,"title":"Proportion to each lot","formula":"measured total / n","calculation_template":"{{meas:f2}} / {{n}}"},{"step_number":3,"title":"Corrected lot frontage","result_template":"{{meas:f2}} / {{n}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Single proportion distributes the surplus/deficiency equally: each lot = measured total / n = {{meas:f2}} / {{n}} = {{_answer}} ft.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000005', 'Cumulative proportion to an interior corner', 'Compute the proportioned distance from a controlling monument to an interior corner.', 'RPLS Practical — Proportionate Measurement', 'Cumulative proportion', 'numeric_input', 'medium', 'Between two controlling original monuments the record total distance is {{recTotal:f2}} ft, but the measured total is {{meas:f2}} ft. By single proportion, what is the corrected distance (ft) from the first monument to an interior corner whose RECORD distance from that monument is {{recToCorner:f2}} ft?', '(round(recTotal*frac,2)/recTotal)*(recTotal+surplus)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"recTotal","type":"float","min":400,"max":900,"decimals":2},{"name":"surplus","type":"float","min":-3,"max":5,"decimals":2},{"name":"frac","type":"float","min":0.3,"max":0.7,"decimals":2}]'::jsonb, '[{"name":"meas","formula":"recTotal+surplus"},{"name":"recToCorner","formula":"round(recTotal*frac,2)"}]'::jsonb, '[{"step_number":1,"title":"Proportion factor","formula":"measured total / record total","calculation_template":"{{meas:f2}} / {{recTotal:f2}}"},{"step_number":2,"title":"Apply to the record distance","formula":"(recToCorner / recTotal) x measured","calculation_template":"({{recToCorner:f2}} / {{recTotal:f2}}) x {{meas:f2}}"},{"step_number":3,"title":"Corrected distance to corner","result_template":"= {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Cumulative single proportion: corrected distance = (record-to-corner / record total) x measured total = ({{recToCorner:f2}} / {{recTotal:f2}}) x {{meas:f2}} = {{_answer}} ft.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000006', 'Gap or overlap width between adjoining lines', 'Compute the gap/overlap width as the difference between two computed line positions along a common line.', 'RPLS Practical — Conflict Resolution', 'Gap and overlap', 'numeric_input', 'easy', 'Along a common reference line, parcel A''s boundary is computed at station {{posA:f2}} ft and the adjoining parcel B''s boundary is computed at station {{posB:f2}} ft. What is the WIDTH (ft) of the gap or overlap between them?', 'abs(posB-posA)', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"posA","type":"float","min":100,"max":300,"decimals":2},{"name":"delta","type":"float","min":0.3,"max":3.5,"decimals":2}]'::jsonb, '[{"name":"posB","formula":"posA+delta"}]'::jsonb, '[{"step_number":1,"title":"Difference of line positions","formula":"|posB - posA|","calculation_template":"|{{posB:f2}} - {{posA:f2}}|"},{"step_number":2,"title":"Gap/overlap width","result_template":"= {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The gap or overlap width is the absolute difference between the two computed line positions: |{{posB:f2}} - {{posA:f2}}| = {{_answer}} ft. If land lies between, it is a gap; if the lines cross, it is an overlap.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000007', 'Tangent length of a simple horizontal curve', 'Compute the tangent distance T of a simple circular curve from its radius and central angle.', 'RPLS Practical — Curves', 'Tangent length', 'numeric_input', 'medium', 'A simple horizontal curve has a radius R = {{R}} ft and an intersection (central) angle I = {{I}} deg. What is the tangent length T (ft) from the PC to the PI?', 'R*tan(toRad(I/2))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"integer","min":400,"max":1500},{"name":"I","type":"integer","min":10,"max":60}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Half the central angle","formula":"I / 2","calculation_template":"{{I}} deg / 2"},{"step_number":2,"title":"Tangent length","result_template":"T = {{R}} x tan({{I}} deg / 2) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The tangent distance from the PC to the PI of a simple curve is T = R tan(I/2) = {{R}} x tan({{I}} deg / 2) = {{_answer}} ft.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
  'eeee2850-0000-0000-0000-000000000008', 'Corrected distance when a monument controls', 'Determine the held distance to a found original monument when it conflicts with the record call.', 'RPLS Practical — Conflict Resolution', 'Monument over distance', 'numeric_input', 'easy', 'A deed calls to run {{rec:f2}} ft to an original iron rod, but the genuine, undisturbed original rod is found at a measured {{meas:f2}} ft. Applying the controlling-monument rule, what distance (ft) do you hold to the corner?', 'rec+diff', '{"decimals":2,"unit":"ft","tolerance":0.01}', '[{"name":"rec","type":"float","min":200,"max":400,"decimals":2},{"name":"diff","type":"float","min":-4,"max":4,"decimals":2}]'::jsonb, '[{"name":"meas","formula":"rec+diff"}]'::jsonb, '[{"step_number":1,"title":"Apply the controlling-monument rule","formula":"monument controls over record distance","calculation_template":"Hold the found rod, not the {{rec:f2}} ft call"},{"step_number":2,"title":"Held distance","result_template":"= {{meas:f2}} ft (the measured distance to the monument)"}]'::jsonb, '{"method":"none"}'::jsonb, 'A found genuine original monument controls over the record distance, so the boundary is held to the rod at {{meas:f2}} ft; the {{rec:f2}} ft call yields. The answer is {{_answer}} ft.', 'c100001c-0000-0000-0000-00000000001c', ARRAY['buildout','module-28','practice']::text[], true, 'buildout:m28');
COMMIT;
SELECT 'm28 RPLS Exam Review — Practical Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c100001c-0000-0000-0000-00000000001c') || ' blocks.' AS status;